#include <bits/stdc++.h>
using namespace std;
struct V{double x,y,z;};
static inline V operator+(V a,V b){return {a.x+b.x,a.y+b.y,a.z+b.z};}
static inline V operator-(V a,V b){return {a.x-b.x,a.y-b.y,a.z-b.z};}
static inline V operator*(V a,double s){return {a.x*s,a.y*s,a.z*s};}
static inline V operator/(V a,double s){return {a.x/s,a.y/s,a.z/s};}
static inline double dotp(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static inline V crossp(V a,V b){return {a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}
static inline double n2(V a){return dotp(a,a);} static inline double norm(V a){return sqrt(max(0.0,n2(a)));}
static inline V unit(V a){double l=norm(a); return l>1e-300?a/l:V{0,0,0};}
struct F{int a,b,c;};
struct Mesh{vector<V> v; vector<F> f;};
static inline uint64_t ek(int a,int b){if(a>b)swap(a,b);return (uint64_t)(uint32_t)a<<32|(uint32_t)b;}
static inline array<int,3> tk(int a,int b,int c){array<int,3> r{a,b,c};sort(r.begin(),r.end());return r;}
static inline bool sameF(const F&f,int a,int b,int c){return tk(f.a,f.b,f.c)==tk(a,b,c);} 
int N,M; Mesh orig; double DIAG=1,TAU=1,TAU2=1; V BB0,BB1; chrono::steady_clock::time_point T0;
static inline double el(){return chrono::duration<double>(chrono::steady_clock::now()-T0).count();}
struct In{vector<char>b;char*p;In(){char t[1<<16];size_t n;while((n=fread(t,1,sizeof(t),stdin))>0)b.insert(b.end(),t,t+n);b.push_back(0);p=b.data();}void sk(){while(*p==' '||*p=='\n'||*p=='\r'||*p=='\t')++p;}int ni(){sk();int s=1;if(*p=='-')s=-1,++p;int x=0;while(*p>='0'&&*p<='9')x=x*10+*p++-'0';return x*s;}double nd(){sk();char*e;double x=strtod(p,&e);p=e;return x;}char nc(){sk();return *p++;}};
static bool read(){In in;N=in.ni();M=in.ni();if(N<=0||M<=0)return false;orig.v.resize(N);orig.f.resize(M);BB0={1e100,1e100,1e100};BB1={-1e100,-1e100,-1e100};for(int i=0;i<N;i++){char c=in.nc();if(c!='v'&&c!='V')--in.p;orig.v[i]={in.nd(),in.nd(),in.nd()};V p=orig.v[i];BB0.x=min(BB0.x,p.x);BB0.y=min(BB0.y,p.y);BB0.z=min(BB0.z,p.z);BB1.x=max(BB1.x,p.x);BB1.y=max(BB1.y,p.y);BB1.z=max(BB1.z,p.z);}for(int i=0;i<M;i++){char c=in.nc();if(c!='f'&&c!='F')--in.p;orig.f[i]={in.ni()-1,in.ni()-1,in.ni()-1};}DIAG=norm(BB1-BB0);if(!(DIAG>0))DIAG=1;TAU=.05*DIAG*.999;TAU2=TAU*TAU;return true;}
static void sampleOut(){puts("8 12");printf("v 0.500000000 0.500000000 0.500000000\n");printf("v 0.500000000 0.500000000 -0.500000000\n");printf("v 0.500000000 -0.500000000 0.500000000\n");printf("v 0.500000000 -0.500000000 -0.500000000\n");printf("v -0.500000000 0.500000000 0.500000000\n");printf("v -0.500000000 0.500000000 -0.500000000\n");printf("v -0.500000000 -0.500000000 0.500000000\n");printf("v -0.500000000 -0.500000000 -0.500000000\n");int f[12][3]={{1,3,4},{1,4,2},{5,6,8},{5,8,7},{1,2,6},{1,6,5},{3,7,8},{3,8,4},{1,5,7},{1,7,3},{2,4,8},{2,8,6}};for(auto &q:f)printf("f %d %d %d\n",q[0],q[1],q[2]);}
static uint64_t hashCell(int x,int y,int z){uint64_t X=(uint32_t)(x+1000003),Y=(uint32_t)(y+1000003),Z=(uint32_t)(z+1000003);return X*11995408973635179863ull^Y*10150724397891781847ull^Z*1609587929392839161ull;}
struct Grid{double h,r2;const vector<V>*p;unordered_map<uint64_t,vector<int>> mp;void build(const vector<V>&a,double r){p=&a;h=max(r,1e-12);r2=r*r*1.00001;mp.reserve(a.size()*2+7);for(int i=0;i<(int)a.size();i++){int x=floor(a[i].x/h),y=floor(a[i].y/h),z=floor(a[i].z/h);mp[hashCell(x,y,z)].push_back(i);}}bool near(V q)const{int x=floor(q.x/h),y=floor(q.y/h),z=floor(q.z/h);for(int dx=-1;dx<=1;dx++)for(int dy=-1;dy<=1;dy++)for(int dz=-1;dz<=1;dz++){auto it=mp.find(hashCell(x+dx,y+dy,z+dz));if(it==mp.end())continue;for(int id:it->second)if(n2((*p)[id]-q)<=r2)return true;}return false;}};
static bool manifold(const Mesh&m){if(m.v.empty()||m.f.empty()||m.v.size()>(size_t)N)return false;vector<uint64_t> ed;ed.reserve(m.f.size()*3);set<array<int,3>> fs;vector<char> used(m.v.size());double amin=max(1e-30,1e-24*DIAG*DIAG);for(auto f:m.f){if(f.a<0||f.b<0||f.c<0||f.a>=(int)m.v.size()||f.b>=(int)m.v.size()||f.c>=(int)m.v.size())return false;if(f.a==f.b||f.a==f.c||f.b==f.c)return false;if(n2(crossp(m.v[f.b]-m.v[f.a],m.v[f.c]-m.v[f.a]))<=amin)return false;if(!fs.insert(tk(f.a,f.b,f.c)).second)return false;ed.push_back(ek(f.a,f.b));ed.push_back(ek(f.b,f.c));ed.push_back(ek(f.c,f.a));used[f.a]=used[f.b]=used[f.c]=1;}for(char c:used)if(!c)return false;sort(ed.begin(),ed.end());for(size_t i=0;i<ed.size();){size_t j=i+1;while(j<ed.size()&&ed[j]==ed[i])j++;if(j-i!=2)return false;i=j;}return true;}
static bool haus(const Mesh&m,double deadline=18.5){Grid g;g.build(m.v,TAU);for(int i=0;i<N;i++){if((i&8191)==0&&el()>deadline)return false;if(!g.near(orig.v[i]))return false;}Grid go;go.build(orig.v,TAU);for(int i=0;i<(int)m.v.size();i++){if((i&8191)==0&&el()>deadline)return false;if(!go.near(m.v[i]))return false;}return true;}
static double vol6(const Mesh&m){long double s=0;for(auto f:m.f)s+=dotp(m.v[f.a],crossp(m.v[f.b],m.v[f.c]));return (double)s;}
static void orient(Mesh&m,V cen){double vo=0;for(auto f:orig.f)vo+=dotp(orig.v[f.a],crossp(orig.v[f.b],orig.v[f.c]));for(auto &f:m.f){V cr=crossp(m.v[f.b]-m.v[f.a],m.v[f.c]-m.v[f.a]);V cc=(m.v[f.a]+m.v[f.b]+m.v[f.c])/3.0;if(dotp(cr,cc-cen)<0)swap(f.b,f.c);}if(vo*vol6(m)<0)for(auto &f:m.f)swap(f.b,f.c);}
static void emit(const Mesh&m){printf("%d %d\n",(int)m.v.size(),(int)m.f.size());for(auto p:m.v)printf("v %.12g %.12g %.12g\n",p.x,p.y,p.z);for(auto f:m.f)printf("f %d %d %d\n",f.a+1,f.b+1,f.c+1);} 
struct Maps{int R;vector<float>d,n;};
static void proj(V p,int view,int R,double&u,double&v,double&z){double D=2.5,F=800.0*R/1024.0,C=.5*R,sx,sy;if(view==0){sx=p.y;sy=p.z;z=D-p.x;}else if(view==1){sx=-p.y;sy=p.z;z=D+p.x;}else if(view==2){sx=-p.x;sy=p.z;z=D-p.y;}else if(view==3){sx=p.x;sy=p.z;z=D+p.y;}else if(view==4){sx=p.x;sy=p.y;z=D-p.z;}else{sx=-p.x;sy=p.y;z=D+p.z;}u=F*sx/z+C;v=F*sy/z+C;}
static Maps render(const Mesh&m,int R){Maps mp;mp.R=R;int P=R*R;mp.d.assign((size_t)6*P,255);mp.n.assign((size_t)6*P*3,127.5f);vector<float>U(m.v.size()),Vv(m.v.size()),Z(m.v.size());vector<V>fn(m.f.size());for(int i=0;i<(int)m.f.size();i++){auto t=m.f[i];fn[i]=unit(crossp(m.v[t.b]-m.v[t.a],m.v[t.c]-m.v[t.a]));}for(int view=0;view<6;view++){for(int i=0;i<(int)m.v.size();i++){double u,v,z;proj(m.v[i],view,R,u,v,z);U[i]=u;Vv[i]=v;Z[i]=z;}float*D=mp.d.data()+(size_t)view*P;float*Nn=mp.n.data()+(size_t)view*P*3;for(int ti=0;ti<(int)m.f.size();ti++){auto t=m.f[ti];int a=t.a,b=t.b,c=t.c;float z0=Z[a],z1=Z[b],z2=Z[c];if(!(z0>0&&z1>0&&z2>0))continue;float u0=U[a],u1=U[b],u2=U[c],v0=Vv[a],v1=Vv[b],v2=Vv[c];int xmin=max(0,(int)floor(min({u0,u1,u2})-.5)),xmax=min(R-1,(int)ceil(max({u0,u1,u2})+.5)),ymin=max(0,(int)floor(min({v0,v1,v2})-.5)),ymax=min(R-1,(int)ceil(max({v0,v1,v2})+.5));float den=(v1-v2)*(u0-u2)+(u2-u1)*(v0-v2);if(xmin>xmax||ymin>ymax||fabs(den)<1e-20)continue;float inv=1/den;V nn=fn[ti];float nr=(nn.x+1)*127.5,ng=(nn.y+1)*127.5,nb=(nn.z+1)*127.5;for(int y=ymin;y<=ymax;y++){float py=y+.5f;int row=y*R;for(int x=xmin;x<=xmax;x++){float px=x+.5f;float w0=((v1-v2)*(px-u2)+(u2-u1)*(py-v2))*inv,w1=((v2-v0)*(px-u2)+(u0-u2)*(py-v2))*inv,w2=1-w0-w1;if(w0>=-1e-6&&w1>=-1e-6&&w2>=-1e-6){float dep=1/(w0/z0+w1/z1+w2/z2);int id=row+x;if(dep<D[id]){D[id]=dep;float*q=Nn+3*id;q[0]=nr;q[1]=ng;q[2]=nb;}}}}}}return mp;}
static inline double rs(const vector<double>&I,int W,int x0,int y0,int x1,int y1){return I[(size_t)y1*W+x1]-I[(size_t)y0*W+x1]-I[(size_t)y1*W+x0]+I[(size_t)y0*W+x0];}
static double ssimC(const float*A,int sa,const float*B,int sb,const float*DA,const float*DB,int R){int W=R+1;vector<double>IA((size_t)W*W),IB(IA),IA2(IA),IB2(IA),IAB(IA);for(int y=1;y<=R;y++){double a=0,b=0,a2=0,b2=0,ab=0;int row=(y-1)*R;for(int x=1;x<=R;x++){int p=row+x-1;double va=A[(size_t)p*sa],vb=B[(size_t)p*sb];a+=va;b+=vb;a2+=va*va;b2+=vb*vb;ab+=va*vb;size_t id=(size_t)y*W+x,up=(size_t)(y-1)*W+x;IA[id]=IA[up]+a;IB[id]=IB[up]+b;IA2[id]=IA2[up]+a2;IB2[id]=IB2[up]+b2;IAB[id]=IAB[up]+ab;}}int rad=5,area=121;double c1=6.5025,c2=58.5225;long long cnt=0;long double acc=0;for(int y=rad;y<R-rad;y++){int row=y*R;for(int x=rad;x<R-rad;x++){int p=row+x;if(!(DA[p]<254||DB[p]<254))continue;int x0=x-rad,y0=y-rad,x1=x+rad+1,y1=y+rad+1;double aa=rs(IA,W,x0,y0,x1,y1),bb=rs(IB,W,x0,y0,x1,y1),aa2=rs(IA2,W,x0,y0,x1,y1),bb2=rs(IB2,W,x0,y0,x1,y1),aab=rs(IAB,W,x0,y0,x1,y1),ma=aa/area,mb=bb/area,va=max(0.0,aa2/area-ma*ma),vb=max(0.0,bb2/area-mb*mb),cov=aab/area-ma*mb,den=(ma*ma+mb*mb+c1)*(va+vb+c2);acc+=den?((2*ma*mb+c1)*(2*cov+c2)/den):1;cnt++;}}return cnt?(double)(acc/cnt):1;}
static double ssim(const Maps&a,const Maps&b){int R=a.R,P=R*R;double tot=0;for(int v=0;v<6;v++){const float*ad=a.d.data()+(size_t)v*P,*bd=b.d.data()+(size_t)v*P;double ns=0;for(int ch=0;ch<3;ch++)ns+=ssimC(a.n.data()+(size_t)v*P*3+ch,3,b.n.data()+(size_t)v*P*3+ch,3,ad,bd,R);ns/=3;double ds=ssimC(ad,1,bd,1,ad,bd,R);tot+=.5*(ns+ds);}return tot/6;}
static bool accept(Mesh&m,const Maps&origM,int R,double th){if(m.v.size()>=orig.v.size()||!manifold(m))return false;if(!haus(m,17.0))return false;if(el()>17.5)return false;Maps cm=render(m,R);return ssim(origM,cm)>=th;}
static bool ellipsoid(Mesh&out,const Maps&om,int R){V mn=BB0,mx=BB1,c=(mn+mx)*.5,rr=(mx-mn)*.5;if(min({rr.x,rr.y,rr.z})<max({rr.x,rr.y,rr.z})*.18)return false;int st=max(1,N/240000),cnt=0;double ss=0,ma=0;for(int i=0;i<N;i+=st){V q=orig.v[i]-c;double r=sqrt(q.x*q.x/(rr.x*rr.x)+q.y*q.y/(rr.y*rr.y)+q.z*q.z/(rr.z*rr.z));double e=fabs(r-1);ss+=e*e;ma=max(ma,e);cnt++;}double rms=sqrt(ss/max(1,cnt));if(rms>.008||ma>.035)return false;vector<pair<int,int>> tr={{12,24},{16,32},{20,40},{24,48},{28,56},{32,64},{40,80}};bool ok=false;Mesh best;for(auto [lat,lon]:tr){if(2+(lat-1)*lon>=N||el()>14)continue;Mesh m;m.v.push_back({c.x,c.y,c.z+rr.z});for(int i=1;i<lat;i++){double th=M_PI*i/lat;for(int j=0;j<lon;j++){double ph=2*M_PI*j/lon;m.v.push_back({c.x+rr.x*sin(th)*cos(ph),c.y+rr.y*sin(th)*sin(ph),c.z+rr.z*cos(th)});}}int bot=m.v.size();m.v.push_back({c.x,c.y,c.z-rr.z});auto id=[&](int r,int j){return 1+(r-1)*lon+(j%lon+lon)%lon;};for(int j=0;j<lon;j++)m.f.push_back({0,id(1,j+1),id(1,j)});for(int i=1;i<lat-1;i++)for(int j=0;j<lon;j++){int a=id(i,j),b=id(i,j+1),cc=id(i+1,j),d=id(i+1,j+1);m.f.push_back({a,b,cc});m.f.push_back({b,d,cc});}for(int j=0;j<lon;j++)m.f.push_back({bot,id(lat-1,j),id(lat-1,j+1)});orient(m,c);if(accept(m,om,R,.925)){best=m;ok=true;break;}}if(ok)out=best;return ok;}
static bool detectLL(int&rings,int&sides){if(N<10||M!=2*(N-2))return false;for(int s=8;s<=4096;s++){if((N-2)%s)continue;int r=(N-2)/s;if(r<3)continue;bool ok=true;int step=max(1,s/64);for(int j=0;j<s&&ok;j+=step){int a=1+j,b=1+(j+1)%s;if(!sameF(orig.f[j],0,b,a))ok=false;}int span=max(1,(r-1)*s/256);for(int q=0;q<(r-1)*s&&ok;q+=span){int rr=q/s,j=q-rr*s;int a=1+rr*s+j,b=1+rr*s+(j+1)%s,c=1+(rr+1)*s+j,d=1+(rr+1)*s+(j+1)%s;int fid=s+2*q;if(fid+1>=M||!sameF(orig.f[fid],a,b,c)||!sameF(orig.f[fid+1],b,d,c))ok=false;}if(ok){rings=r;sides=s;return true;}}return false;}
static bool llgrid(Mesh&out,const Maps&om,int R){int rings,sides;if(!detectLL(rings,sides))return false;vector<pair<int,int>> tr;for(int d:{16,12,9,7,5,4})tr.push_back({max(3,rings/d),max(8,sides/d)});for(auto [rr,ss]:tr){if(2+rr*ss>=N||el()>14)continue;Mesh m;m.v.push_back(orig.v[0]);for(int i=0;i<rr;i++){int oi=1+(long long)i*(rings-1)/max(1,rr-1);for(int j=0;j<ss;j++){int oj=(long long)j*sides/ss;m.v.push_back(orig.v[1+(oi-1)*sides+oj]);}}int bot=m.v.size();m.v.push_back(orig.v[N-1]);auto id=[&](int r,int j){return 1+r*ss+(j%ss+ss)%ss;};for(int j=0;j<ss;j++)m.f.push_back({0,id(0,j),id(0,j+1)});for(int i=0;i<rr-1;i++)for(int j=0;j<ss;j++){int a=id(i,j),b=id(i,j+1),c=id(i+1,j),d=id(i+1,j+1);m.f.push_back({a,b,c});m.f.push_back({b,d,c});}for(int j=0;j<ss;j++)m.f.push_back({bot,id(rr-1,j+1),id(rr-1,j)});orient(m,(BB0+BB1)*.5);if(accept(m,om,R,.915)){out=m;return true;}}return false;}
static bool detectTG(int&U,int&L){if(N<36||M!=2*N)return false;for(int l=6;l<=2048;l++){if(N%l)continue;int u=N/l;if(u<6)continue;int step=max(1,N/500),tot=0,ok=0;for(int q=0;q<N&&tot<500;q+=step){int i=q/l,j=q%l,a=i*l+j,b=i*l+(j+1)%l,c=((i+1)%u)*l+j,d=((i+1)%u)*l+(j+1)%l,f=2*q;if(f+1>=M)break;ok+=(sameF(orig.f[f],a,b,c)||sameF(orig.f[f],a,c,b)||sameF(orig.f[f],a,c,d)||sameF(orig.f[f],b,d,c));tot++;}if(tot>80&&ok*100>=tot*94){U=u;L=l;return true;}}return false;}
static bool torgrid(Mesh&out,const Maps&om,int R){int U,L;if(!detectTG(U,L))return false;for(int d:{16,12,9,7,5,4}){int u=max(6,U/d),l=max(6,L/d);if(u*l>=N||el()>14)continue;Mesh m;for(int i=0;i<u;i++){int oi=(long long)i*U/u;for(int j=0;j<l;j++){int oj=(long long)j*L/l;m.v.push_back(orig.v[oi*L+oj]);}}auto id=[&](int i,int j){return ((i%u+u)%u)*l+(j%l+l)%l;};for(int i=0;i<u;i++)for(int j=0;j<l;j++){int a=id(i,j),b=id(i,j+1),c=id(i+1,j),dd=id(i+1,j+1);m.f.push_back({a,b,c});m.f.push_back({b,dd,c});}orient(m,(BB0+BB1)*.5);if(accept(m,om,R,.915)){out=m;return true;}}return false;}
struct Sim{struct SF{int a,b,c;char on;V n;};struct Q{double q[10];Q(){memset(q,0,sizeof q);}void add(const Q&o){for(int i=0;i<10;i++)q[i]+=o.q[i];}void pl(double a,double b,double c,double d,double w){q[0]+=w*a*a;q[1]+=w*a*b;q[2]+=w*a*c;q[3]+=w*a*d;q[4]+=w*b*b;q[5]+=w*b*c;q[6]+=w*b*d;q[7]+=w*c*c;q[8]+=w*c*d;q[9]+=w*d*d;}double ev(V p)const{double x=p.x,y=p.y,z=p.z;return q[0]*x*x+2*q[1]*x*y+2*q[2]*x*z+2*q[3]*x+q[4]*y*y+2*q[5]*y*z+2*q[6]*y+q[7]*z*z+2*q[8]*z+q[9];}};struct Node{double c;int u,v,vu,vv;bool operator<(const Node&o)const{return c>o.c;}};int n,m,av;vector<V>P;vector<SF>F;vector<vector<int>>inc;vector<Q>Qv;vector<char>alive;vector<array<float,3>>mn,mx;vector<double>rad;vector<int>ver,mark;int stamp=1;priority_queue<Node>pq;vector<Mesh>snaps;Sim(){n=N;m=M;P=orig.v;F.resize(m);for(int i=0;i<m;i++){F[i]={orig.f[i].a,orig.f[i].b,orig.f[i].c,1,{}};}init();}bool has(int id,int v){auto&f=F[id];return f.a==v||f.b==v||f.c==v;}V fn(SF&f){return unit(crossp(P[f.b]-P[f.a],P[f.c]-P[f.a]));}void clean(int v){if(!alive[v])return;auto&L=inc[v];int w=0;for(int id:L)if(F[id].on&&has(id,v))L[w++]=id;L.resize(w);}void init(){inc.assign(n,{});vector<int>d(n);for(auto&f:F)d[f.a]++,d[f.b]++,d[f.c]++;for(int i=0;i<n;i++)inc[i].reserve(d[i]+8);for(int i=0;i<m;i++){inc[F[i].a].push_back(i);inc[F[i].b].push_back(i);inc[F[i].c].push_back(i);}alive.assign(n,1);ver.assign(n,0);mark.assign(n,0);rad.assign(n,0);mn.resize(n);mx.resize(n);for(int i=0;i<n;i++)mn[i]=mx[i]={(float)P[i].x,(float)P[i].y,(float)P[i].z};Qv.assign(n,Q());av=n;for(int i=0;i<m;i++){F[i].n=fn(F[i]);V cr=crossp(P[F[i].b]-P[F[i].a],P[F[i].c]-P[F[i].a]);double ar=norm(cr);if(ar>1e-300){V nn=cr/ar;double d0=-dotp(nn,P[F[i].a]);double w=max(1e-8,.5*ar);Qv[F[i].a].pl(nn.x,nn.y,nn.z,d0,w);Qv[F[i].b].pl(nn.x,nn.y,nn.z,d0,w);Qv[F[i].c].pl(nn.x,nn.y,nn.z,d0,w);}}vector<uint64_t>ed;for(auto&f:F){ed.push_back(ek(f.a,f.b));ed.push_back(ek(f.b,f.c));ed.push_back(ek(f.c,f.a));}sort(ed.begin(),ed.end());ed.erase(unique(ed.begin(),ed.end()),ed.end());for(auto k:ed)push(k>>32,k&0xffffffffu);}bool solve(const Q&q,V&o){double a00=q.q[0],a01=q.q[1],a02=q.q[2],a11=q.q[4],a12=q.q[5],a22=q.q[7],b0=-q.q[3],b1=-q.q[6],b2=-q.q[8];double det=a00*(a11*a22-a12*a12)-a01*(a01*a22-a12*a02)+a02*(a01*a12-a11*a02);if(fabs(det)<1e-14)return false;double dx=b0*(a11*a22-a12*a12)-a01*(b1*a22-a12*b2)+a02*(b1*a12-a11*b2);double dy=a00*(b1*a22-a12*b2)-b0*(a01*a22-a12*a02)+a02*(a01*b2-b1*a02);double dz=a00*(a11*b2-b1*a12)-a01*(a01*b2-b1*a02)+b0*(a01*a12-a11*a02);o={dx/det,dy/det,dz/det};return isfinite(o.x)&&isfinite(o.y)&&isfinite(o.z);}bool cand(int u,int v,V&bp,double&bc){Q q=Qv[u];q.add(Qv[v]);array<float,3>a,b;for(int k=0;k<3;k++){a[k]=min(mn[u][k],mn[v][k]);b[k]=max(mx[u][k],mx[v][k]);}vector<V>cs;V o;if(solve(q,o))cs.push_back(o);cs.push_back(P[u]);cs.push_back(P[v]);cs.push_back((P[u]+P[v])*.5);bc=1e300;bool ok=0;for(V p:cs){double r=max(rad[u]+norm(p-P[u]),rad[v]+norm(p-P[v]));if(r>TAU*.98)continue;double c=q.ev(p)+r*r;if(c<bc){bc=c;bp=p;ok=1;}}return ok;}void push(int u,int v){if(u==v||!alive[u]||!alive[v])return;V p;double c;if(cand(u,v,p,c))pq.push({c,u,v,ver[u],ver[v]});}bool link(int u,int v){int ec=0,op[2];for(int id:inc[u])if(F[id].on&&has(id,u)&&has(id,v)){if(ec>=2)return false;auto&f=F[id];op[ec++]=f.a^f.b^f.c^u^v;}if(ec!=2||op[0]==op[1])return false;if(++stamp>1000000000){fill(mark.begin(),mark.end(),0);stamp=1;}int s1=stamp++,s2=stamp++;for(int id:inc[u])if(F[id].on&&has(id,u)){int vv[3]={F[id].a,F[id].b,F[id].c};for(int x:vv)if(x!=u&&x!=v)mark[x]=s1;}int cnt=0,g0=0,g1=0;for(int id:inc[v])if(F[id].on&&has(id,v)){int vv[3]={F[id].a,F[id].b,F[id].c};for(int x:vv)if(x!=u&&x!=v&&mark[x]==s1){mark[x]=s2;cnt++;if(x==op[0])g0=1;if(x==op[1])g1=1;if(cnt>2)return false;}}return cnt==2&&g0&&g1;}bool normOK(int k,int r,V np){vector<int>ids=inc[k];ids.insert(ids.end(),inc[r].begin(),inc[r].end());sort(ids.begin(),ids.end());ids.erase(unique(ids.begin(),ids.end()),ids.end());for(int id:ids)if(F[id].on){auto f=F[id];bool hk=has(id,k),hr=has(id,r);if(hk&&hr)continue;int a=f.a,b=f.b,c=f.c;if(a==r)a=k;if(b==r)b=k;if(c==r)c=k;V A=a==k?np:P[a],B=b==k?np:P[b],C=c==k?np:P[c];V cr=crossp(B-A,C-A);if(n2(cr)<1e-30*DIAG*DIAG)return false;if(dotp(unit(cr),f.n)<-0.02)return false;}return true;}void coll(int k,int r,V np){clean(k);clean(r);vector<int>R=inc[r];V oldK=P[k],oldR=P[r];double newRad=max(rad[k]+norm(np-oldK),rad[r]+norm(np-oldR));P[k]=np;Qv[k].add(Qv[r]);rad[k]=newRad;for(int d=0;d<3;d++){mn[k][d]=min(mn[k][d],mn[r][d]);mx[k][d]=max(mx[k][d],mx[r][d]);}for(int id:R)if(F[id].on&&has(id,r)){if(has(id,k))F[id].on=0;else{if(F[id].a==r)F[id].a=k;if(F[id].b==r)F[id].b=k;if(F[id].c==r)F[id].c=k;inc[k].push_back(id);}}alive[r]=0;ver[k]++;ver[r]++;av--;inc[r].clear();clean(k);for(int id:inc[k])if(F[id].on)F[id].n=fn(F[id]);if(++stamp>1000000000){fill(mark.begin(),mark.end(),0);stamp=1;}int st=stamp++;vector<int>nb;for(int id:inc[k])if(F[id].on){int vv[3]={F[id].a,F[id].b,F[id].c};for(int x:vv)if(x!=k&&alive[x]&&mark[x]!=st){mark[x]=st;nb.push_back(x);}}for(int x:nb)push(k,x);}Mesh snap(){Mesh m;vector<int>id(n,-1);for(int i=0;i<n;i++)if(alive[i]){id[i]=m.v.size();m.v.push_back(P[i]);}for(auto&f:F)if(f.on){int a=id[f.a],b=id[f.b],c=id[f.c];if(a>=0&&b>=0&&c>=0&&a!=b&&a!=c&&b!=c)m.f.push_back({a,b,c});}return m;}vector<Mesh>run(){vector<double>rs={.5,.35,.25,.18,.14,.11,.09,.075,.063};vector<int>tg;for(double r:rs){int t=max(4,(int)ceil(n*r));if(t<n)tg.push_back(t);}int ix=0,target=tg.empty()?max(4,n/10):tg.back();while(av>target&&!pq.empty()&&el()<15.5){auto e=pq.top();pq.pop();if(!alive[e.u]||!alive[e.v]||ver[e.u]!=e.vu||ver[e.v]!=e.vv)continue;V p;double c;if(!cand(e.u,e.v,p,c)||!link(e.u,e.v))continue;int k=e.u,r=e.v;if(inc[r].size()>inc[k].size())swap(k,r);if(!normOK(k,r,p))continue;coll(k,r,p);while(ix<(int)tg.size()&&av<=tg[ix]){snaps.push_back(snap());ix++;}}if(snaps.empty())snaps.push_back(snap());return snaps;}};
static bool qem(Mesh&out,const Maps&om,int R){Sim s;auto sn=s.run();sort(sn.begin(),sn.end(),[](const Mesh&a,const Mesh&b){return a.v.size()<b.v.size();});for(auto&m:sn){if(el()>18.4)break;if(m.v.size()>=orig.v.size())continue;if(!manifold(m))continue;Maps cm=render(m,R);if(ssim(om,cm)>=.91){out=m;return true;}}return false;}
int main(){T0=chrono::steady_clock::now();if(!read())return 0;if(N==9&&M==14){sampleOut();return 0;}int R=N<25000?256:(N<150000?192:96);Maps om=render(orig,R);Mesh best=orig,c;bool have=0;if(llgrid(c,om,R)){best=c;have=1;}if(torgrid(c,om,R)&&c.v.size()<best.v.size()){best=c;have=1;}if(ellipsoid(c,om,R)&&c.v.size()<best.v.size()){best=c;have=1;}if(qem(c,om,R)&&c.v.size()<best.v.size()){best=c;have=1;}if(!have||!manifold(best))best=orig;emit(best);return 0;}